={{ (() => {
  const ai = JSON.parse($json.message.content);
  return JSON.stringify({
    date: $now.format('yyyy-MM-dd'),
    file_code_name: ai.file_code_name,
    title_concept: ai.title_concept,
    hook: ai.hook_text,
    script: ai.voiceover_script,
    status: 'Pending',
    hook_visual_prompt: ai.hook_visual_prompt,
    veo_prompts: ai.veo_motion_prompts.join(' ||| '),
    nano_prompts: ai.nano_banana_prompts.join(' ||| '),
    easter_egg: ai.easter_egg
  });
})() }}

